VALUES
  ('locality-d0d1b9a2-moex-00424', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-111-ac2adf20', 'sub-locality-d0d1b9a2-02', NULL, 'single_choice', '依政府會計準則公報之規定，下列敘述何者錯誤？', '["政府財務報表之表首，應清楚表達報導個體名稱", "政府整體財務報表之編製，採用權責發生基礎", "政府整體財務報表，至少應包括整體收支表及整體資產負債表", "作業基金財務報表，原則依民營事業適用之一般公認會計原則編製"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:09+00:00", "source_pdf_sha1": "91c2d8a44a43", "answer_pdf_sha1": "d0503f971105", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "315", "s": "1507", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00425', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-111-ac2adf20', 'sub-locality-d0d1b9a2-02', NULL, 'single_choice', '行政院於會計年度結束後，依規定編製總決算送審計機關查核，審計機關對於各機關違背預算或 有關法令之不當支出，得事後剔除追繳之，依中央政府普通公務單位會計制度之一致規定，機關 於收到剔除不當支出時應為之會計分錄：', '["借：應收剔除經費，貸：業務支出", "借：應收剔除經費，貸：資產負債淨額", "借：繳付公庫數，貸：應收剔除經費", "借：公庫撥入數，貸：應收剔除經費"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:09+00:00", "source_pdf_sha1": "91c2d8a44a43", "answer_pdf_sha1": "d0503f971105", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "315", "s": "1507", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00426', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-111-ac2adf20', 'sub-locality-d0d1b9a2-02', NULL, 'single_choice', '甲機關於X1年2月5日與民間機構簽訂委辦契約辦理政府施政滿意度計畫，並依契約規定預先 撥付調查費500,000元；簽約後甲機關擬減少施作次數及樣本數，於X1年5月1日與該機構協 議修改合約，並依修正後合約收回預付款項 150,000 元，作為當年預算所定用途繼續支用，試依 中央政府普通公務單位會計制度之一致規定，甲機關於收回該筆款項時應為之會計分錄：', '["借：繳付公庫數150,000元，貸：其他應收款150,000元", "借：繳付公庫數150,000元，貸：預付款150,000元", "借：公庫撥入數150,000元，貸：其他應收款150,000元", "借：公庫撥入數150,000元，貸：預付款150,000元"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:09+00:00", "source_pdf_sha1": "91c2d8a44a43", "answer_pdf_sha1": "d0503f971105", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "315", "s": "1507", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00427', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-111-ac2adf20', 'sub-locality-d0d1b9a2-02', NULL, 'single_choice', '依中央公共債務會計制度之規定，下列有關其經理機構之敘述，何者正確？', '["依業務需要設預算控制類科目", "會計年度之開始及終了，依決算法規定辦理", "依據相關經理辦法，對公債及國庫券之核結，不設會計科目", "會計基礎採用權責發生制；在平時採用現金收付制者，決算時應照權責發生制予以調整"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:09+00:00", "source_pdf_sha1": "91c2d8a44a43", "answer_pdf_sha1": "d0503f971105", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "315", "s": "1507", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00428', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-111-ac2adf20', 'sub-locality-d0d1b9a2-02', NULL, 'single_choice', '中央政府甲機關補助乙直轄市政府200萬元，並依約分二期分別撥付款項，甲機關於次年度進行 查核時，發現該補助計畫執行後尚有賸餘款15萬元，爰要求收回補助賸餘款，依中央政府普通公 務單位會計制度之一致規定，甲機關於收回補助賸餘款並繳庫應為之會計分錄：', '["借：公庫撥入數15萬元，貸：其他收入15萬元", "借：繳付公庫數15萬元，貸：資產負債淨額15萬元", "借：繳付公庫數15萬元，貸：補助直轄市政府15萬元", "借：公庫撥入數15萬元，貸：資產負債淨額15萬元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:09+00:00", "source_pdf_sha1": "91c2d8a44a43", "answer_pdf_sha1": "d0503f971105", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "315", "s": "1507", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00429', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-111-ac2adf20', 'sub-locality-d0d1b9a2-02', NULL, 'single_choice', 'A廠商之化學原料於X9年10月1日外漏污染鄰近農地，預估整治復原經費為$2,000,000，A廠 商負有整治受污染農地之義務，惟為加速復原進度，甲機關同日公開聲明將協助A廠商整治受污 染農地，後續代墊款項，將由A廠商歸墊，依政府會計準則公報規定，X9年10月1日甲機關應 為之會計處理：', '["無須處理", "借：業務支出$2,000,000，貸：公庫撥入數$2,000,000", "借：暫付款$2,000,000，貸：公庫撥入數$2,000,000", "借：業務支出$2,000,000，貸：應付帳款$2,000,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:09+00:00", "source_pdf_sha1": "91c2d8a44a43", "answer_pdf_sha1": "d0503f971105", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "315", "s": "1507", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00430', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-111-ac2adf20', 'sub-locality-d0d1b9a2-02', NULL, 'single_choice', '甲機關經管之保安林於 X9 年 3 月 15 日發生大火，依法甲機關須負責重建，預估重建經費為 $1,300,000，悉屬業務支出，依中央政府普通公務單位會計制度之一致規定，甲機關應為之分錄：', '["借：業務支出$1,300,000，貸：負債準備$1,300,000", "借：業務支出$1,300,000，貸：應付帳款$1,300,000", "借：業務支出$1,300,000，貸：公庫撥入數$1,300,000", "僅須於會計報告揭露必要資訊"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:09+00:00", "source_pdf_sha1": "91c2d8a44a43", "answer_pdf_sha1": "d0503f971105", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "315", "s": "1507", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00431', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-111-ac2adf20', 'sub-locality-d0d1b9a2-02', NULL, 'single_choice', '依中央公共債務會計制度之規定，受託辦理實體公債還本付息業務者，係指經理行之何種委託機 構？', '["清算銀行及其經辦行", "承轉行及其經辦行", "承貸單位", "經辦行"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:09+00:00", "source_pdf_sha1": "91c2d8a44a43", "answer_pdf_sha1": "d0503f971105", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "315", "s": "1507", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
