  ('locality-d0d1b9a2-moex-00433', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-111-ac2adf20', 'sub-locality-d0d1b9a2-02', NULL, 'single_choice', '依現行徵課會計實務，甲國稅局於108年底於認列將於次年5月以後收取之應收稅款500萬元， 並估計有20萬元無法收回，應做之會計分錄為何？', '["借記應收稅款480萬元及貸記稅課收入480萬元", "借記應收稅款500萬元及貸記備底呆稅─應收稅款20萬元與貸記遞延收入480萬元", "借記應收稅款500萬元及貸記備底呆稅─應收稅款20萬元與貸記稅課收入480萬元", "借記應收稅款480萬元及貸記遞延收入480萬元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:09+00:00", "source_pdf_sha1": "91c2d8a44a43", "answer_pdf_sha1": "d0503f971105", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "315", "s": "1507", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL)
